CREATE OR REPLACE FUNCTION what_quarter_is(date_in date, start_month integer DEFAULT 1)
RETURNS integer AS $$
BEGIN
    RETURN ((EXTRACT(MONTH FROM date_in) - start_month + 12) % 12) / 3 + 1;
END;
$$ LANGUAGE plpgsql;

-- Example usage:
SELECT what_quarter_is('1995-07-23'::date, 4)

CREATE OR REPLACE FUNCTION log_player_name_changes() 
RETURNS trigger AS $BODY$
BEGIN
    IF NEW.player_name <> OLD.player_name THEN
        INSERT INTO player_audits(player_id, old_player_name, changed_on)
        VALUES(OLD.player_api_id, OLD.player_name, now());
    END IF;
    RETURN NEW;
END;
$BODY$ LANGUAGE plpgsql;

CREATE TRIGGER tr_change_playername
AFTER UPDATE OF player_name ON player
FOR EACH ROW
EXECUTE PROCEDURE log_player_name_changes()

DROP FUNCTION IF EXISTS update_school_inventory_after_supply() CASCADE;

CREATE OR REPLACE FUNCTION update_school_inventory_after_supply() 
RETURNS TRIGGER 
LANGUAGE plpgsql 
AS $trigger$ 
BEGIN 
    UPDATE school_inventory 
    SET quantity = quantity + NEW.quantity 
    WHERE cdscode = NEW.cdscode 
      AND supply_name = NEW.supply_name;

    RETURN NEW; 
END; 
$trigger$;

DROP TRIGGER IF EXISTS trigger_insert_supply ON school_supplies;

CREATE TRIGGER trigger_insert_supply 
AFTER INSERT ON school_supplies 
FOR EACH ROW 
EXECUTE FUNCTION update_school_inventory_after_supply()

CREATE OR REPLACE FUNCTION calculate_loan_status()
    RETURNS SETOF loan_last
    AS $$
    BEGIN
        CREATE TEMPORARY TABLE temp_table AS
        SELECT loan_id, status FROM loan_first WHERE status = 'A';

        INSERT INTO loan_last
        SELECT loan_id, status FROM temp_table;

        RETURN QUERY SELECT * FROM loan_last;
    END;
    $$ LANGUAGE plpgsql

