CREATE OR REPLACE FUNCTION fn_concat(f_name character varying, l_name character varying) 
RETURNS character varying AS $$
BEGIN
    IF f_name IS NULL AND l_name IS NULL THEN
        RETURN NULL;
    ELSEIF f_name IS NULL AND l_name IS NOT NULL THEN
        RETURN l_name;
    ELSEIF f_name IS NOT NULL AND l_name IS NULL THEN
        RETURN f_name;
    ELSE
        RETURN CONCAT(f_name, ' ', l_name);
    END IF;
END;
$$ LANGUAGE plpgsql;

