    l_name, 
    email AS email_address, 
    fn_concat(f_name, l_name) AS full_name 
FROM cust

CREATE OR REPLACE FUNCTION reindex_superhero_ids(publisher_id_param BIGINT) RETURNS VOID LANGUAGE plpgsql AS $$
BEGIN
    -- Create a temporary sequence
    CREATE TEMPORARY SEQUENCE id_seq_temp MINVALUE 1 START WITH 1 INCREMENT BY 1;

    -- Restart the sequence to ensure it starts at 1
    PERFORM nextval('id_seq_temp');
    ALTER SEQUENCE id_seq_temp RESTART WITH 1;

    -- Shift existing hair_colour_ids out of the way to avoid unique constraint violations
    UPDATE superhero
    SET hair_colour_id = hair_colour_id + 2000
    WHERE publisher_id = publisher_id_param;

    -- Reindex the hair_colour_ids using the temporary sequence
    UPDATE superhero
    SET hair_colour_id = nextval('id_seq_temp')
    WHERE publisher_id = publisher_id_param;
END;
$$

