-- Part 1: Corrected DO block demonstrating the logic on a variable
DO $$
DECLARE
    _info TEXT := '{"client_id":1,"gender":"F"}';
    _output_info TEXT;
    _info_jsonb JSONB;
BEGIN
    -- Attempt to parse and update
    BEGIN
        -- Cast text to JSONB. This will raise an exception if _info is not valid JSON.
        _info_jsonb := _info::jsonb;

        -- Check if 'gender' key exists and its value is 'F'
        IF _info_jsonb ? 'gender' AND (_info_jsonb ->> 'gender') = 'F' THEN
            -- Update the value to 'M'
            _info_jsonb := jsonb_set(_info_jsonb, '{gender}', '"M"'::jsonb);
        END IF;

        -- Convert back to text
        _output_info := _info_jsonb::text;

    EXCEPTION
        WHEN others THEN
            -- If invalid JSON or any other error occurs, keep the original text
            _output_info := _info;
    END;

    -- Output the result (using RAISE NOTICE to see it in console logs)
    RAISE NOTICE 'Result: %', _output_info;

    -- Optional: Store in a temp table as requested in the original script
    CREATE TEMP TABLE IF NOT EXISTS _json_update_result (info TEXT);
    TRUNCATE TABLE _json_update_result;
    INSERT INTO _json_update_result (info) VALUES (_output_info);
END $$;

