DROP TABLE IF EXISTS "EventCategories";

CREATE TABLE "EventCategories"(
    "ID" INT GENERATED ALWAYS AS IDENTITY PRIMARY KEY, 
    "IsBusinessCategory" BOOLEAN NULL
);

DROP TABLE IF EXISTS "BusinessCategories";

CREATE TABLE "BusinessCategories"(
    "ID" INT GENERATED ALWAYS AS IDENTITY PRIMARY KEY, 
    "BusinessCategoryID" INT NOT NULL REFERENCES "EventCategories"("ID")
);

-- Create a function to check the condition
CREATE OR REPLACE FUNCTION check_business_category_flag()
RETURNS TRIGGER AS $$
BEGIN
    -- Check if the referenced EventCategory exists and has IsBusinessCategory = true
    IF NOT EXISTS (
        SELECT 1 
        FROM "EventCategories" 
        WHERE "ID" = NEW."BusinessCategoryID" 
        AND "IsBusinessCategory" IS TRUE
    ) THEN
        RAISE EXCEPTION 'Cannot link to EventCategory ID (%) because it is not a valid business category (IsBusinessCategory is not true).', NEW."BusinessCategoryID";
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Create the trigger on BusinessCategories
CREATE TRIGGER trg_enforce_business_category_link
BEFORE INSERT OR UPDATE ON "BusinessCategories"
FOR EACH ROW
EXECUTE FUNCTION check_business_category_flag()

